window.__QUIZ_DATA__=[{"id":"objective>Civic Education>2021>1","subject":"Civic Education","year":"2021","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : DEFINITION","question":"The deliberate effort to avoid behaving abnormally when faced with pressure can be termed","images":[],"options":{"A":"self esteem","B":"self control","C":"integrity","D":"determination"},"answer":"B","explanation":"The deliberate effort to avoid behaving abnormally when faced with pressure can be termed as 'self control'. Self control is the ability to control oneself, in particular one's emotions and desires or the expression of them in one's behavior, especially in difficult situations.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2021>2","subject":"Civic Education","year":"2021","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF CITIZENSHIP","question":"The categories of Nigerian citizens that cannot be declared as non-citizens under any circumstances are citizens by","images":[],"options":{"A":"parentage and naturalization","B":"registration and birth","C":"birth and parentage","D":"registration and naturalization"},"answer":"C","explanation":"The categories of Nigerian citizens that cannot be declared as non-citizens under any circumstances are citizens by 'birth and parentage'. This is because citizenship by birth and parentage is irrevocable, unlike citizenship by registration and naturalization which can be revoked under certain circumstances.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2021>3","subject":"Civic Education","year":"2021","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : IMPORTANCE OF RESPONSIBLE PARENTHOOD IN NATIONAL DEVELOPMENT","question":"An importance of effective parenting is that it ensures","images":[],"options":{"A":"adequate formal education of the citizen","B":"provision of secondary needs for the family","C":"family members know how to socialize","D":"morally upright wards are bred for the society"},"answer":"D","explanation":"Effective parenting ensures that children are raised in a manner that they become morally upright citizens. This is because parents are the first moral compass for children and their actions and teachings greatly influence the child's character and behavior. Therefore, the correct answer is 'morally upright wards are bred for the society'.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2021>4","subject":"Civic Education","year":"2021","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS","question":"A ban on public lectures and symposiums is against the right to freedom of","images":[],"options":{"A":"movement and right to speech","B":"worship and fair hearing","C":"electronic and print media","D":"peaceful assembly and association"},"answer":"D","explanation":"A ban on public lectures and symposiums is against the right to freedom of peaceful assembly and association. This is because these activities are forms of peaceful assembly where people come together to discuss, learn, and share ideas. Therefore, the correct answer is 'peaceful assembly and association'.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2021>5","subject":"Civic Education","year":"2021","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS","question":"All these can be a cause of accident on the road except","images":[],"options":{"A":"praying while driving","B":"eating while driving","C":"being conscious of road signs","D":"taking alcohol before driving"},"answer":"C","explanation":"Being conscious of road signs is not a cause of accidents on the road. On the contrary, it is a safety measure that helps to prevent accidents. The other options, such as praying while driving, eating while driving, and taking alcohol before driving, can cause distractions or impair the driver's ability to operate the vehicle safely, thereby leading to accidents.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2021>6","subject":"Civic Education","year":"2021","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : DEFINITION","question":"Use the quotation below to answer question below  'Being truthful to oneself;   being truthful to others;   being someone others can trust;   doing what is right regardless   of the circumstances.\"   The above quotation is apt for describing","images":[],"options":{"A":"selflessness","B":"diligence","C":"discipline","D":"integrity"},"answer":"D","explanation":"The quotation describes the concept of integrity. Integrity involves being truthful to oneself and others, being trustworthy, and doing what is right regardless of the circumstances. The other options, such as selflessness, diligence, and discipline, do not fully capture the essence of the quotation.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2021>7","subject":"Civic Education","year":"2021","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : WAYS OF PROMOTING NATIONAL CONSCIOUSNESS, INTEGRITY AND UNITY IN THE SOCIETY","question":"National consciousness, unity and integrity are promoted through all the following ways except","images":[],"options":{"A":"obedience to rules and regulations","B":"National Youth Service Corps","C":"compromise of the rule of law","D":"teaching of Civic Education in schools"},"answer":"C","explanation":"National consciousness, unity and integrity are promoted through obedience to rules and regulations, National Youth Service Corps, and teaching of Civic Education in schools. However, the compromise of the rule of law does not promote national consciousness, unity, and integrity. The rule of law is a principle that ensures all individuals, including the government, are subject to law that is fairly applied and enforced. Compromising it would lead to injustice and inequality, which are against national consciousness, unity, and integrity.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2021>8","subject":"Civic Education","year":"2021","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : MEANING AND ORIGIN OF CULTISM","question":"Membership of an organization associated with secrecy of operations in the society is an indication of","images":[],"options":{"A":"activism","B":"cultism","C":"radicalism","D":"spiritism"},"answer":"B","explanation":"Membership of an organization associated with secrecy of operations in the society is an indication of cultism. Cultism involves activities of secret cults or societies that are kept secret from non-members. These groups often have secret signs, symbols, or codes and may be involved in illegal activities. Activism, radicalism, and spiritism do not necessarily involve secrecy of operations in the society.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2021>9","subject":"Civic Education","year":"2021","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTER-COMMUNAL RELATIONSHIPS","question":"Associations, connections and affiliations between two or more group is what type of relationship?","images":[],"options":{"A":"Intra-group","B":"Inter-communal","C":"Interpersonal","D":"Intra-communal"},"answer":"B","explanation":"The question is asking about the type of relationship between two or more groups. The correct answer is 'Inter-communal'. 'Inter-' is a prefix meaning 'between', 'among', or 'mutually', so 'inter-communal' refers to relationships or interactions between different communities or groups. 'Intra-' on the other hand, is a prefix meaning 'within' or 'inside', so 'intra-group' and 'intra-communal' refer to relationships within a single group or community. 'Interpersonal' refers to relationships or interactions between individuals, not groups.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2021>10","subject":"Civic Education","year":"2021","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY","question":"Orderliness in society is best guaranteed when all citizens","images":[],"options":{"A":"obey rules and regulations","B":"respect and humble themselves","C":"are proud to be associated with the society","D":"know the sanctions for violations of laws"},"answer":"A","explanation":"The question is asking about what guarantees orderliness in society. The correct answer is 'obey rules and regulations'. This is because rules and regulations are established to maintain order and harmony in a society. When all citizens obey these rules and regulations, it ensures that everyone's actions are predictable and consistent, which in turn promotes orderliness. The other options, while they may contribute to a harmonious society, do not directly guarantee orderliness.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2021>11","subject":"Civic Education","year":"2021","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS","question":"Use the images in the diagram to answer question below            The traffic sign in the images in the diagram is to caution road drivers that","images":["data:image/png;base64,"],"options":{"A":"pedestrians crossing is in progress therefore, all cars should wait patiently for them","B":"a designed bus-stop is ahead where school children can be picked and dropped","C":"pedestrians are to hold hands together so as to support one another when crossing","D":"they need to move fast because of the presence of a school zone"},"answer":"A","explanation":"Pedestrian crossing signs are posted near crosswalks and intersections and posted in school zones. Both signs use yellow-green fluorescent reflective sheeting that enhances its visibility on the roads.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2021>12","subject":"Civic Education","year":"2021","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : FUNCTIONS OF GOVERNMENT","question":"Paying our taxes and assisting the government in the fight against crime are examples of","images":[],"options":{"A":"civil obligations","B":"social obligations","C":"economic obligations","D":"cultural obligations"},"answer":"A","explanation":"Paying taxes and assisting the government in the fight against crime are examples of civil obligations. Civil obligations refer to the duties that citizens are expected to perform in their society. These duties include obeying the law, paying taxes, and assisting in the fight against crime.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2021>13","subject":"Civic Education","year":"2021","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : MEANING OF YOUTH EMPOWERMENT","question":"Creating an enabling environment for someone to have control over his financial situation is known as","images":[],"options":{"A":"reinforcement","B":"endowment","C":"empowerment","D":"enhancement"},"answer":"C","explanation":"Creating an enabling environment for someone to have control over his financial situation is known as empowerment. Empowerment refers to the process of becoming stronger and more confident, especially in controlling one's life and claiming one's rights. In this context, it refers to financial empowerment, which involves giving an individual the ability to manage and control their financial situation.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2021>14","subject":"Civic Education","year":"2021","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : WAYS OF PROMOTING NATIONAL CONSCIOUSNESS, INTEGRITY AND UNITY IN THE SOCIETY","question":"The following are steps towards sustaining national unity except","images":[],"options":{"A":"emphasis on factors that unite a nation","B":"respecting the national symbols","C":"discouraging inter-religious marriages","D":"working towards achieving national objectives"},"answer":"C","explanation":"National unity is sustained by emphasizing factors that unite a nation, respecting national symbols, and working towards achieving national objectives. However, discouraging inter-religious marriages does not contribute to national unity. Instead, it promotes division and discrimination among different religious groups. Therefore, the correct answer is option 3.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2021>15","subject":"Civic Education","year":"2021","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTER-PERSONAL RELATIONSHIPS","question":"A major reason that fosters healthy interpersonal relationship is","images":[],"options":{"A":"pursuit of money","B":"party politics","C":"common goals","D":"culture"},"answer":"C","explanation":"Healthy interpersonal relationships are fostered by common goals. When individuals or groups share common goals, they are more likely to work together, communicate effectively, and resolve conflicts in a manner that strengthens their relationship. The pursuit of money and party politics can often lead to conflicts and unhealthy competition, while culture can sometimes be a source of division. Therefore, the correct answer is option 3.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2021>16","subject":"Civic Education","year":"2021","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : STIGMATIZATION OF PEOPLE LIVING WITH HIV/AIDS","question":"People Living with HIV/AIDS (PLWHA) are stigmatized by","images":[],"options":{"A":"refusal of privileges","B":"exploitation by care givers","C":"refusal to be voted for in election","D":"refusing to respect their authority"},"answer":"A","explanation":"People Living with HIV/AIDS (PLWHA) are often stigmatized by society in various ways. One of these ways is through the refusal of privileges. This can include being denied access to certain services, opportunities, or rights due to their health status. This form of discrimination contributes to the marginalization and stigmatization of PLWHA.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2021>17","subject":"Civic Education","year":"2021","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : CATEGORIES OF HUMAN RIGHTS","question":"A child who is forced to engage in hawking all day must have been denied the right to","images":[],"options":{"A":"fair hearing","B":"expression","C":"education","D":"life"},"answer":"C","explanation":"A child who is forced to engage in hawking all day is being denied the right to education. The United Nations Convention on the Rights of the Child, to which most countries are signatories, stipulates that every child has the right to education. Forcing a child to hawk all day prevents the child from going to school and receiving an education, thereby denying them this fundamental right.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2021>18","subject":"Civic Education","year":"2021","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : MEANING OF YOUTH EMPOWERMENT","question":"The sole aim of youth empowerment is to","images":[],"options":{"A":"encourage students to take on a vacation job","B":"learn to earn money and also how to manage it","C":"learn how to behave in a work related environment","D":"give youths financial independence and self reliance"},"answer":"D","explanation":"Youth empowerment is a process where young people are encouraged to take charge of their lives. They do this by addressing their situation and then take action in order to improve their access to resources and transform their consciousness through their beliefs, values, and attitudes. The ultimate goal of youth empowerment is to improve the socio-economic status of the youth, which includes financial independence and self-reliance. Therefore, the correct answer is 'give youths financial independence and self reliance'.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2021>19","subject":"Civic Education","year":"2021","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : MEANING OF HUMAN TRAFFICKING","question":"Use the passage below to answer questions below    One day she met some friends who capitalized on her situation and advised her to leave home if she wanted to live good life and she obliged; she was introduced to a trafficking agent who took her abroad where she was compelled to engage in prostitution. Five years later, Chalyn was deported after she had contracted the deadly HIV/AIDS.    - From the above passage, it could be inferred that Chalyn is majorly a victim of","images":[],"options":{"A":"human trafficking","B":"inconsiderate government","C":"lack of family planning","D":"non-payment of salaries"},"answer":"A","explanation":"From the passage, it is clear that Chalyn was introduced to a trafficking agent who took her abroad where she was compelled to engage in prostitution. This is a clear case of human trafficking, which is the action or practice of illegally transporting people from one country or area to another, typically for the purposes of forced labour or commercial sexual exploitation. Therefore, the correct answer is 'human trafficking'.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2021>20","subject":"Civic Education","year":"2021","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : CAUSES OF HUMAN TRAFFICKING","question":"Use the passage below to answer questions below    One day she met some friends who capitalized on her situation and advised her to leave home if she wanted to live good life and she obliged; she was introduced to a trafficking agent who took her abroad where she was compelled to engage in prostitution. Five years later, Chalyn was deported after she had contracted the deadly HIV/AIDS.   Which of the following would have likely saved Chalyn from falling into the hands of traffickers?","images":[],"options":{"A":"Adequate remunerations for civil servants","B":"An established family business","C":"Moral upbringing and solid parental care","D":"Adequate family planning"},"answer":"C","explanation":"From the passage, it can be inferred that Chalyn was vulnerable due to her situation and was easily influenced by her friends to leave home. If she had received moral upbringing and solid parental care, she might have been able to make better decisions and not fall into the hands of traffickers. Moral upbringing refers to the process of teaching a child the difference between right and wrong, and solid parental care refers to the provision of a safe, nurturing environment by parents.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2021>21","subject":"Civic Education","year":"2021","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFORTS OF GOVERNMENT AND INDIVIDUALS IN STOPPING HUMAN TRAFFICKING","question":"Use the passage below to answer questions below    One day she met some friends who capitalized on her situation and advised her to leave home if she wanted to live good life and she obliged; she was introduced to a trafficking agent who took her abroad where she was compelled to engage in prostitution. Five years later, Chalyn was deported after she had contracted the deadly HIV/AIDS.   Chalyn's ordeal would have been likely prevented through all the following means except","images":[],"options":{"A":"poverty alleviation programme","B":"effective family planning","C":"qualitative higher education","D":"skill acquisition courses"},"answer":"B","explanation":"The passage suggests that Chalyn's ordeal was a result of her being trafficked and forced into prostitution. While poverty alleviation, qualitative higher education, and skill acquisition courses could potentially prevent such a situation by providing alternative means of livelihood, effective family planning is not directly related to preventing human trafficking. Family planning generally refers to the practice of controlling the number of children in a family and the intervals between their births, which doesn't directly impact the likelihood of being trafficked.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2021>22","subject":"Civic Education","year":"2021","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS","question":"Which of the following agents is not saddled with the responsibility of maintaining traffic regulation in Nigeria?","images":[],"options":{"A":"Vehicle Inspection Officer","B":"Nigerian Customs Officer","C":"Police Traffic Warden","D":"Corps Marshal"},"answer":"B","explanation":"The Nigerian Customs Officer is not responsible for maintaining traffic regulation in Nigeria. Their primary role is to manage the import and export of goods, collect customs revenue and prevent smuggling. The Vehicle Inspection Officer, Police Traffic Warden, and Corps Marshal are all involved in maintaining traffic regulation.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2021>23","subject":"Civic Education","year":"2021","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : CAUSES OF HIV/AIDS","question":"A society that is free from HIV/AIDS infected persons will likely experience","images":[],"options":{"A":"increase in level of poverty","B":"increase in productivity","C":"loss of man power","D":"high deah rate"},"answer":"B","explanation":"A society that is free from HIV/AIDS infected persons will likely experience an increase in productivity. This is because the absence of the disease means that more people are healthy and able to contribute to the workforce, leading to increased productivity. The other options such as increase in level of poverty, loss of man power, and high death rate are more likely to be associated with a society that has a high prevalence of HIV/AIDS.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2021>24","subject":"Civic Education","year":"2021","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS","question":"Major behavioural manifestations of drug addicts include the following except","images":[],"options":{"A":"mental disorder","B":"isolation and withdrawal","C":"depression and regrets","D":"humility and boldness"},"answer":"D","explanation":"Drug addiction often leads to various behavioral changes such as mental disorders, isolation and withdrawal, and depression and regrets. However, humility and boldness are not typically associated with drug addiction. In fact, drug addicts often exhibit the opposite behaviors, such as arrogance and fearfulness.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2021>25","subject":"Civic Education","year":"2021","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT","question":"The lowest court in Nigeria is the","images":[],"options":{"A":"Magistrate/District Court","B":"Court of Appeal","C":"Sharia Court of Appeal","D":"State High Court"},"answer":"A","explanation":"In the Nigerian judicial system, the Magistrate/District Court is considered the lowest court. It is the first point of call for most civil and criminal cases. The Court of Appeal, Sharia Court of Appeal, and State High Court are higher courts in the hierarchy.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2021>26","subject":"Civic Education","year":"2021","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT","question":"Which of the following has the power to impeach the president in Nigeria?","images":[],"options":{"A":"Executive","B":"Judiciary","C":"Legislature","D":"Supreme court"},"answer":"C","explanation":"In Nigeria, the power to impeach the president lies with the Legislature. The process begins in the House of Representatives and if a resolution is passed by two-thirds majority of all its members, it is sent to the Senate for further deliberation and investigation. If the Senate also passes the resolution by two-thirds majority, the president is successfully impeached.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2021>27","subject":"Civic Education","year":"2021","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTER-PERSONAL RELATIONSHIPS","question":"The phrase no man is an island............means that","images":[],"options":{"A":"mankind needs other plants and animals to survive","B":"citizens cannot operate without help of a government","C":"individuals need the cooperation of others to progress","D":"humans need to marry and have life partners"},"answer":"C","explanation":"The phrase 'no man is an island' is a proverb that emphasizes the interdependence of humans. It means that humans do not thrive when isolated from others and need to be part of a community in order to survive. It implies that individuals need the cooperation of others to progress in life.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2021>28","subject":"Civic Education","year":"2021","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : YOUTH EMPOWERMENT SKILLS","question":"Use the image in the diagram to answer questions below         The people depicted in the image in the diagram are engaged in","images":["data:image/png;base64,"],"options":{"A":"community service","B":"personal development","C":"empowerment scheme","D":"fashion design competition"},"answer":"C","explanation":"Empowerment is the degree of autonomy and self determination in people and communities. This enables them to represent their interest in a responsible and self-determined way, acting on their own authority. It is a key concept in the discourse on promoting civic engagement.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2021>29","subject":"Civic Education","year":"2021","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : YOUTH EMPOWERMENT SKILLS","question":"Use the image in the diagram to answer questions below         The aim of those engaged in the activity captured in the image in Figure 2 is to","images":["data:image/png;base64,"],"options":{"A":"obtain relevant skills","B":"acquire formal knowledge","C":"source for extra income","D":"develop interpersonal skills"},"answer":"A","explanation":"Empowerment is letting the power out. It encourages people to gain the skills and knowledge that will allow them to overcome obstacles in life or work environment and ultimately, help them develop within themselves or in the society.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2021>30","subject":"Civic Education","year":"2021","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : YOUTH EMPOWERMENT SKILLS","question":"Use the image in the diagram to answer questions below         Which type of skill is dominant in the image in figure 2?","images":["data:image/png;base64,"],"options":{"A":"Manipulative Skill","B":"Intellectual Skill","C":"Negotiation Skill","D":"Communicative Skill"},"answer":"A","explanation":"Manipulative skill is the ability to manipulate a thing or an object with the help of the body or a body part e.g kicking, throwing, bouncing etc.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2021>31","subject":"Civic Education","year":"2021","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : GOALS OF CITIZENSHIP EDUCATION","question":"Citizenship education ensures that citizens become aware of","images":[],"options":{"A":"tenets of the laws of the society","B":"attributes required to become a leader","C":"how to restore peace during conflict","D":"justice and injustice during litigation"},"answer":"A","explanation":"Citizenship education is a type of education that prepares citizens to become informed, thoughtful, and active citizens of their communities. It is designed to instill good civic virtues and habits in the citizens, making them aware of the tenets of the laws of the society. This includes understanding the rights, responsibilities, and privileges of citizenship, as well as how to exercise these rights and responsibilities in a variety of contexts.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2021>32","subject":"Civic Education","year":"2021","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM","question":"Cultism is usually not associated with","images":[],"options":{"A":"rustication","B":"academic excellence","C":"stigmatization","D":"spiritual problems"},"answer":"B","explanation":"Cultism is a social vice that is associated with negative outcomes such as rustication, stigmatization, and spiritual problems. However, it is not associated with academic excellence. In fact, involvement in cultism often leads to poor academic performance due to the time and energy that cult activities demand, as well as the potential for disciplinary actions such as suspension or expulsion from school.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2021>33","subject":"Civic Education","year":"2021","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT","question":"The programmes political parties intend to implement if they are voted into power are known as political","images":[],"options":{"A":"campaigns","B":"manifestoes","C":"agenda","D":"propaganda"},"answer":"B","explanation":"The programmes political parties intend to implement if they are voted into power are known as political manifestoes. A political manifesto is a public declaration of policies and aims, especially one issued before an election by a political party or candidate.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2021>34","subject":"Civic Education","year":"2021","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : MEANING OF POLITICAL APATHY","question":"Use the dialogue below to answer questions below  Mr. Ganaba: Mr Katoun, where are you   going with the hoe and cutlass   on a day that has been set aside for the rescheduled   gubernatorial election in our state?   Mr. Katoun: I am going to the farm   to harvest some tubers of   yam for the next market   day. I don't need to remind   you that we have been   made our own governemt.   Therefore, the sale of   this product is much more   beneficial to me and my   family than whoever   becomes the next governor.    From the dialogue above, Mr Katoun has demonstrated","images":[],"options":{"A":"survival mode","B":"intolerance","C":"apathy","D":"hard work"},"answer":"C","explanation":"From the dialogue, Mr Katoun has demonstrated apathy. Apathy is a lack of interest, enthusiasm, or concern. In this context, Mr Katoun shows a lack of interest in the gubernatorial election, choosing instead to focus on his farming activities.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2021>35","subject":"Civic Education","year":"2021","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : ACHIEVING POPULAR PARTICIPATION IN POLITICS","question":"Use the dialogue below to answer questions below  Mr. Ganaba: Mr Katoun, where are you   going with the hoe and cutlass   on a day that has been set aside for the rescheduled   gubernatorial election in our state?   Mr. Katoun: I am going to the farm   to harvest some tubers of   yam for the next market   day. I don't need to remind   you that we have been   made our own governemt.   Therefore, the sale of   this product is much more   beneficial to me and my   family than whoever   becomes the next governor.   As seen in the dialogue above, Mr. Ganabe is involved in an essential community service as","images":[],"options":{"A":"a social mobilizer","B":"a political analyst","C":"an election observer","D":"a party official"},"answer":"A","explanation":"From the dialogue, Mr. Ganaba is seen questioning Mr. Katoun about his decision to go to the farm on an election day. This shows that he is trying to mobilize Mr. Katoun to participate in the election, hence he is acting as a social mobilizer. A social mobilizer is someone who motivates others to take part in a particular activity or cause.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2021>36","subject":"Civic Education","year":"2021","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : CAUSES OF POLITICAL APATHY","question":"Use the dialogue below to answer questions below  Mr. Ganaba: Mr Katoun, where are you   going with the hoe and cutlass   on a day that has been set aside for the rescheduled   gubernatorial election in our state?   Mr. Katoun: I am going to the farm   to harvest some tubers of   yam for the next market   day. I don't need to remind   you that we have been   made our own governemt.   Therefore, the sale of   this product is much more   beneficial to me and my   family than whoever   becomes the next governor.   The behaviour of Mr.Katoun in the dialogue above can be traced to the following factors except","images":[],"options":{"A":"inadequate security at polling booths","B":"poor technology","C":"unfulfilled manifestoes","D":"existence of endemic corruption"},"answer":"B","explanation":"From the dialogue, Mr. Katoun's decision to go to the farm instead of participating in the election is not directly linked to any of the provided options. His decision seems to be more influenced by his personal belief that his farming activities are more beneficial to him and his family than the outcome of the election. Therefore, none of the options provided correctly explains Mr. Katoun's behavior.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2021>37","subject":"Civic Education","year":"2021","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT","question":"The constitution of the Federal Republic of Nigeria from 1979 to 1999 have all been","images":[],"options":{"A":"written and rigid","B":"written and flexible","C":"unwritten and rigid","D":"unwritten and flexible"},"answer":"A","explanation":"The constitutions of the Federal Republic of Nigeria from 1979 to 1999 have all been written and rigid. A written constitution is a formal document defining the nature of the constitutional settlement, the rules that govern the political system and the rights of citizens and governments in a codified form. A rigid constitution is one that requires a special procedure for its amendment or revision, usually involving a higher degree of difficulty than for ordinary laws.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2021>38","subject":"Civic Education","year":"2021","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : FUNCTIONS OF PUBLIC SERVICE","question":"An established way Labour Unions protect the interest of workers is","images":[],"options":{"A":"police action","B":"hunger strike","C":"industrial action","D":"mass resignation"},"answer":"C","explanation":"Labour Unions protect the interest of workers through industrial action. Industrial action is taken by employees or workers when there is a dispute that cannot be resolved by negotiation. It involves activities undertaken by unionized workers to express their dissatisfaction, including strikes, work-to-rule, go-slow, or other actions designed to reduce productivity.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2021>39","subject":"Civic Education","year":"2021","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : CATEGORIES OF HUMAN RIGHTS","question":"The right to vie for public office falls under","images":[],"options":{"A":"economic rights","B":"political rights","C":"social rights","D":"religious right"},"answer":"B","explanation":"The right to vie for public office falls under political rights. Political rights are rights that allow individuals to freely participate in the political process, including the right to vote, the right to free speech, and the right to vie for public office. These rights are fundamental to a functioning democracy.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2021>40","subject":"Civic Education","year":"2021","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING, TYPES, AND FEATURES OF DEMOCRACY;","question":"The system of government where the ultimate power resides in the people is","images":[],"options":{"A":"plutocracy","B":"aristocracy","C":"theocracy","D":"democracy"},"answer":"D","explanation":"The system of government where the ultimate power resides in the people is democracy. In a democracy, citizens have the power to elect their leaders and influence the policies of their government. This is in contrast to other forms of government like plutocracy (rule by the wealthy), aristocracy (rule by a privileged class), and theocracy (rule by religious leaders).","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2021>41","subject":"Civic Education","year":"2021","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : MEANING OF POLITICAL APATHY","question":"Politically enlightened people may still feel discouraged in the political affairs of their society because of political","images":[],"options":{"A":"selflessness","B":"contentment","C":"participation","D":"marginalization"},"answer":"D","explanation":"Political marginalization refers to the process where certain individuals or groups are pushed to the edge of society by not allowing them an active voice, identity, or place in it. This can lead to them feeling discouraged in the political affairs of their society.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2021>42","subject":"Civic Education","year":"2021","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT","question":"Supervisory Councilors at the local government level are part of the","images":[],"options":{"A":"civil servants","B":"executive organ","C":"legislature organ","D":"judicial organ"},"answer":"B","explanation":"Supervisory Councilors at the local government level are part of the executive organ. The executive organ is the part of government that has sole authority and responsibility for the daily administration of the state. It executes, or enforces the law. The division of power into separate branches of government is central to the idea of the separation of powers.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2021>43","subject":"Civic Education","year":"2021","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT","question":"Constitutional provisions cannot be derived from","images":[],"options":{"A":"statutory sources","B":"customary sources","C":"judicial precedents","D":"colonial policies"},"answer":"D","explanation":"Constitutional provisions are the laws and guidelines as stated in a country's constitution. They can be derived from statutory sources, customary sources, and judicial precedents. Statutory sources refer to laws enacted by the legislative arm of government. Customary sources refer to the customs and traditions of the people which have been accepted over time. Judicial precedents refer to previous court decisions that are used as a guide in similar future cases. However, colonial policies cannot be a source of constitutional provisions because they are the policies imposed by colonial masters during the colonial era and may not reflect the values, customs, and traditions of the people.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2021>44","subject":"Civic Education","year":"2021","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : ACHIEVING POPULAR PARTICIPATION IN POLITICS","question":"Political participation is facilitated by the following reasons except","images":[],"options":{"A":"engaging in moral upliftment","B":"fostering of political stability","C":"enhancement of dividends of democracy","D":"influencing the direction of government policies"},"answer":"A","explanation":"Political participation refers to the activities that citizens engage in, to influence the selection of political leaders and the policies they make. These activities include voting, campaigning, lobbying, etc. While political participation can foster political stability, enhance the dividends of democracy, and influence the direction of government policies, engaging in moral upliftment is not a direct way of facilitating political participation. Moral upliftment refers to the improvement of one's moral standards and it's more of a personal development activity rather than a political one.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2021>45","subject":"Civic Education","year":"2021","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE AND ROLES OF CONSTITUTED AUTHORITY","question":"Which of these societal values is most expected of every public office holder?","images":[],"options":{"A":"Excellence","B":"Accountability","C":"Hospitality","D":"Diplomacy"},"answer":"B","explanation":"Accountability is the most expected societal value of every public office holder. This is because public office holders are entrusted with public resources and power, and they are expected to use these resources and power responsibly, transparently, and in the best interest of the public. Accountability ensures that public office holders are answerable for their actions and decisions, and can be held responsible if they misuse their power or resources.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2021>46","subject":"Civic Education","year":"2021","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING, TYPES, AND FEATURES OF DEMOCRACY;","question":"Constitutional democracy is also known as","images":[],"options":{"A":"limited government","B":"communalism","C":"communism","D":"absolute government"},"answer":"A","explanation":"Constitutional democracy is also known as limited government. In a constitutional democracy, the power of the government is limited by the constitution, which protects the rights and freedoms of the citizens. This is in contrast to an absolute government, where the government has unlimited power and can do whatever it wants without any checks or balances.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2021>47","subject":"Civic Education","year":"2021","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : PROBLEMS OF PUBLIC SERVICE","question":"Use the cartoon in the diagram to answer questions below         The phrase the music has changed refers to the fact that","images":["data:image/png;base64,"],"options":{"A":"checks and balances are no longer effective","B":"public servants are to show partisanship","C":"there was corruption in the public service sector","D":"the activities of the judiciary should be checkmated"},"answer":"C","explanation":"The phrase the music has changed refers to the fact that there was corruption in the public service sector.","marks":"1","difficulty":"3"},{"id":"objective>Civic Education>2021>48","subject":"Civic Education","year":"2021","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : PROBLEMS OF PUBLIC SERVICE","question":"Use the cartoon in the diagram to answer questions below         The first statement in the cartoon affirms that the speaker was","images":["data:image/png;base64,"],"options":{"A":"supportive of constituted authority","B":"jealous of Chief Jeunkoku's wealth","C":"aiding and abetting corruption","D":"discouraging injustice in the land"},"answer":"C","explanation":"The first statement indicate \" aiding and abetting corruption\"","marks":"1","difficulty":"3"},{"id":"objective>Civic Education>2021>49","subject":"Civic Education","year":"2021","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PROBLEMS OF RULE OF LAW","question":"Use the cartoon in the diagram to answer questions below         A way Chief Jeunkoku can evade sanction is if there is","images":["data:image/png;base64,"],"options":{"A":"presence of checks and balances","B":"operational principle of rule of law","C":"supremacy of the constitution","D":"a weak and comprised judiciary"},"answer":"D","explanation":"Chief Jeunkoku can evade sanction is if there is a weak and comprised judiciary.","marks":"1","difficulty":"3"},{"id":"objective>Civic Education>2021>50","subject":"Civic Education","year":"2021","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF CIVIL SOCIETY","question":"Which of the following is not a feature of civil society?","images":[],"options":{"A":"Protection of the interest of society","B":"Voluntary membership and participation","C":"Respect for constituted authority","D":"Soliciting for political patronage"},"answer":"D","explanation":"Civil society is characterized by voluntary membership and participation, protection of the interest of society, and respect for constituted authority. However, soliciting for political patronage is not a feature of civil society. Civil society organizations are typically independent of government and do not seek political patronage.","marks":"1","difficulty":"2"}];